// ── Globe wireframe lines ────────────────────────────────────────────────────
function GlobeWireframe() {
  const groupRef = useRef<THREE.Group>(null)
  useFrame((s, dt) => {
    if (groupRef.current) groupRef.current.rotation.y += dt * 0.04
  })

  const lines = useMemo(() => {
    const geoms: THREE.BufferGeometry[] = []
    const R = 2.6
    // Lat lines
    for (let lat = -75; lat <= 75; lat += 25) {
      const phi = (lat * Math.PI) / 180
      const pts: THREE.Vector3[] = []
      for (let i = 0; i <= 64; i++) {
        const theta = (i / 64) * Math.PI * 2
        pts.push(new THREE.Vector3(
          R * Math.cos(phi) * Math.cos(theta),
          R * Math.sin(phi),
          R * Math.cos(phi) * Math.sin(theta)
        ))
      }
      geoms.push(new THREE.BufferGeometry().setFromPoints(pts))
    }
    // Lon lines
    for (let lon = 0; lon < 360; lon += 30) {
      const theta = (lon * Math.PI) / 180
      const pts: THREE.Vector3[] = []
      for (let i = 0; i <= 64; i++) {
        const phi = ((i / 64) * 180 - 90) * (Math.PI / 180)
        pts.push(new THREE.Vector3(
          R * Math.cos(phi) * Math.cos(theta),
          R * Math.sin(phi),
          R * Math.cos(phi) * Math.sin(theta)
        ))
      }
      geoms.push(new THREE.BufferGeometry().setFromPoints(pts))
    }
    return geoms
  }, [])

  return (
    <group ref={groupRef}>
      {lines.map((geom, i) => (
        <line key={i}>
          <primitive object={geom} />
          <lineBasicMaterial color="#f97316" transparent opacity={0.08} />
        </line>
      ))}
    </group>
  )
}

// ── Floating icon node ────────────────────────────────────────────────────────
interface IconDef { name: string; color: string; bg: string; svg: string }

function FloatingIcon({ icon, basePos, mvSpeed }: {
  icon: IconDef
  basePos: THREE.Vector3
  mvSpeed: React.MutableRefObject<number>
}) {
  const groupRef = useRef<THREE.Group>(null)
  const velRef = useRef(new THREE.Vector3())
  const posRef = useRef(basePos.clone())
  const phaseRef = useRef(Math.random() * Math.PI * 2)

  useFrame((scene, dt) => {
    if (!groupRef.current) return

    phaseRef.current += dt * 0.4

    // Gentle orbit offset
    const wobble = new THREE.Vector3(
      Math.sin(phaseRef.current * 0.7) * 0.12,
      Math.cos(phaseRef.current * 0.5) * 0.12,
      Math.sin(phaseRef.current * 0.6) * 0.08,
    )

    const target = basePos.clone().add(wobble)

    // Mouse velocity scatter
    const mv = mvSpeed.current
    if (mv > 0.05) {
      const dir = posRef.current.clone().normalize()
      velRef.current.addScaledVector(dir, mv * 12 + 2)
    }

    // Spring back
    const spring = target.clone().sub(posRef.current).multiplyScalar(2.5)
    velRef.current.addScaledVector(spring, dt)
    velRef.current.multiplyScalar(0.87)
    posRef.current.addScaledVector(velRef.current, dt)

    groupRef.current.position.copy(posRef.current)
    groupRef.current.lookAt(scene.camera.position)
  })

  return (
    <group ref={groupRef}>
      {/* Icon HTML */}
      <Html center distanceFactor={8} zIndexRange={[0, 10]} style={{ pointerEvents: 'none' }}>
        <div style={{
          width: '36px',
          height: '36px',
          borderRadius: '10px',
          background: icon.bg,
          border: `1.5px solid ${icon.color}40`,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          boxShadow: `0 0 14px ${icon.color}30, 0 0 4px ${icon.color}20 inset`,
          color: icon.color,
          padding: '6px',
          backdropFilter: 'blur(4px)',
        }}>
          <div style={{ width: '100%', height: '100%' }} dangerouslySetInnerHTML={{ __html: icon.svg }} />
        </div>
      </Html>
      {/* Dot at node */}
      <mesh>
        <sphereGeometry args={[0.04, 6, 6]} />
        <meshBasicMaterial color={icon.color} transparent opacity={0.7} />
      </mesh>
    </group>
  )
}

// ── Distribute icons on sphere surface ──────────────────────────────────────
function distributeOnSphere(n: number, r: number): THREE.Vector3[] {
  const pts: THREE.Vector3[] = []
  const golden = Math.PI * (3 - Math.sqrt(5))
  for (let i = 0; i < n; i++) {
    const y = 1 - (i / (n - 1)) * 2
    const radius = Math.sqrt(1 - y * y)
    const theta = golden * i
    pts.push(new THREE.Vector3(r * radius * Math.cos(theta), r * y, r * radius * Math.sin(theta)))
  }
  return pts
}

// ── Core gem ─────────────────────────────────────────────────────────────────
function CoreGem({ mvSpeed }: { mvSpeed: React.MutableRefObject<number> }) {
  const ref = useRef<THREE.Group>(null)
  const innerRef = useRef<THREE.Mesh>(null)
  const glowRef = useRef<THREE.Mesh>(null)
  const { mouse } = useThree()

  useFrame((s, dt) => {
    if (!ref.current) return
    ref.current.rotation.y += (0.15 + mvSpeed.current * 3) * dt
    ref.current.rotation.x = THREE.MathUtils.lerp(ref.current.rotation.x, mouse.y * 0.4, 0.04)

    if (innerRef.current) {
      innerRef.current.rotation.y -= 0.25 * dt
      innerRef.current.rotation.x += 0.1 * dt
    }

    if (glowRef.current) {
      const gMat = glowRef.current.material as THREE.MeshBasicMaterial
      gMat.opacity = 0.04 + Math.sin(s.clock.elapsedTime * 1.5) * 0.02 + mvSpeed.current * 0.08
    }
  })

  return (
    <group ref={ref}>
      {/* Outer transparent sphere */}
      <Sphere args={[2.6, 32, 32]}>
        <meshStandardMaterial
          color="#1a0a00"
          transparent
          opacity={0.18}
          roughness={0.05}
          metalness={0.9}
          side={THREE.FrontSide}
        />
      </Sphere>

      {/* Inner gem */}
      <mesh ref={innerRef}>
        <icosahedronGeometry args={[1.1, 1]} />
        <meshStandardMaterial
          color="#b84d08"
          emissive="#5a1c00"
          emissiveIntensity={0.5}
          metalness={0.95}
          roughness={0.05}
          flatShading
        />
      </mesh>

      {/* Octahedron core */}
      <mesh>
        <octahedronGeometry args={[0.42]} />
        <meshStandardMaterial
          color="#f97316"
          emissive="#f97316"
          emissiveIntensity={0.9}
          metalness={0.6}
          roughness={0.1}
        />
      </mesh>

      {/* Glow sphere */}
      <mesh ref={glowRef}>
        <sphereGeometry args={[1.4, 16, 16]} />
        <meshBasicMaterial color="#f97316" transparent opacity={0.05} side={THREE.BackSide} />
      </mesh>

      <pointLight color="#f97316" intensity={3} distance={7} />
      <pointLight color="#ff9f5e" intensity={1} distance={4} />
    </group>
  )
}

// ── Mouse velocity tracker ───────────────────────────────────────────────────
function MouseVelocity({ mvRef }: { mvRef: React.MutableRefObject<number> }) {
  const prev = useRef(new THREE.Vector2())
  useFrame(({ mouse }) => {
    const dx = mouse.x - prev.current.x
    const dy = mouse.y - prev.current.y
    const raw = Math.sqrt(dx * dx + dy * dy) * 60
    mvRef.current = THREE.MathUtils.lerp(mvRef.current, Math.min(raw, 1), 0.18)
    prev.current.copy(mouse)
  })
  return null
}

// ── Main export ───────────────────────────────────────────────────────────────
export default function TechGlobe() {
  const mvRef = useRef(0)
  const positions = useMemo(() => distributeOnSphere(TECH_ICONS.length, 2.6), [])

  return (
    <div className="w-full h-full">
      <Canvas camera={{ position: [0, 0, 6.5], fov: 42 }} dpr={[1, 2]} gl={{ antialias: true, alpha: true }}>
        <MouseVelocity mvRef={mvRef} />
        <ambientLight intensity={0.1} />
        <pointLight position={[6, 4, 6]} intensity={1.5} color="#f97316" />
        <pointLight position={[-5, -3, -4]} intensity={0.6} color="#818cf8" />
        <directionalLight position={[0, 8, 3]} intensity={0.8} color="#fff5ee" />
        <Stars radius={55} depth={30} count={1400} factor={1.8} saturation={0} fade speed={0.3} />

        {/* Wireframe globe */}
        <GlobeWireframe />

        {/* Central gem */}
        <CoreGem mvSpeed={mvRef} />

        {/* Floating tech icons */}
        {TECH_ICONS.map((icon, i) => (
          <FloatingIcon key={icon.name} icon={icon} basePos={positions[i]} mvSpeed={mvRef} />
        ))}

        {/* OrbitControls — mouse rotate */}
        <OrbitControls
          enablePan={false}
          enableZoom={false}
          enableDamping
          dampingFactor={0.05}
          rotateSpeed={0.4}
          autoRotate
          autoRotateSpeed={0.5}
        />
      </Canvas>
    </div>
  )
}
